"""Data models for the e-commerce system."""
from dataclasses import dataclass, field
from typing import Optional
from enum import Enum

class OrderStatus(Enum):
    PENDING = "pending"
    CONFIRMED = "confirmed"
    SHIPPED = "shipped"
    DELIVERED = "delivered"
    CANCELLED = "cancelled"

@dataclass
class User:
    id: int
    name: str
    email: str
    is_premium: bool = False

@dataclass
class Product:
    id: int
    name: str
    price: float
    stock: int
    category: str = "general"

@dataclass
class OrderItem:
    product: Product
    quantity: int

    @property
    def subtotal(self):
        return self.product.price * self.quantity

@dataclass
class Order:
    id: int
    user: User
    items: list = field(default_factory=list)
    status: OrderStatus = OrderStatus.PENDING
    discount_pct: float = 0.0

    def add_item(self, product, quantity):
        self.items.append(OrderItem(product, quantity))

    @property
    def subtotal(self):
        return sum(item.subtotal for item in self.items)

    @property
    def total(self):
        discount = self.subtotal * (self.discount_pct / 100)
        return round(self.subtotal - discount, 2)

setup_files.validators.py:
"""Input validation for orders and users."""

def validate_order(order):
    """Validate order before confirmation. Returns (is_valid, errors)."""
    errors = []

    if not order.items:
        errors.append("Order must have at least one item")

    for item in order.items:
        if item.quantity <= 0:
            errors.append(f"Invalid quantity for {item.product.name}")
        # Bug: checks stock BEFORE quantity, should be quantity > stock
        if item.product.stock < 0:
            errors.append(f"Insufficient stock for {item.product.name}")

    if order.discount_pct < 0 or order.discount_pct > 100:
        errors.append("Discount must be between 0 and 100")

    return len(errors) == 0, errors

def validate_email(email):
    """Basic email validation."""
    if not email or "@" not in email:
        return False
    parts = email.split("@")
    if len(parts) != 2:
        return False
    local, domain = parts
    if not local or not domain or "." not in domain:
        return False
    return True

setup_files.repository.py:
"""In-memory data storage."""

class Repository:
    def __init__(self):
        self.users = {}
        self.orders = {}
        self._next_user_id = 1
        self._next_order_id = 1

    def next_user_id(self):
        uid = self._next_user_id
        self._next_user_id += 1
        return uid

    def next_order_id(self):
        oid = self._next_order_id
        self._next_order_id += 1
        return oid

    def save_user(self, user):
        self.users[user.id] = user

    def save_order(self, order):
        self.orders[order.id] = order

    def get_user(self, user_id):
        return self.users.get(user_id)

    def get_order(self, order_id):
        return self.orders.get(order_id)

    def get_user_orders(self, user_id):
        return [o for o in self.orders.values() if o.user.id == user_id]
